const body = $input.first().json.body || $input.first().json;

const hostname   = body.vm_name || body.hostname || 'unknown';
const location   = body.location || 'not set';
const primaryIp  = (body.ip && body.ip.primary) ? body.ip.primary : 'unknown';
const ram        = body.ram  || {};
const osType     = body.os_type || 'linux';
const allMounts  = (body.disk && body.disk.all_mounts) ? body.disk.all_mounts : [];
const rootDisk   = (body.disk && body.disk.root) ? body.disk.root : {};
const hasIssues  = body.has_issues === true;
const issues     = body.resource_issues || [];
const timestamp  = body.timestamp || '';
const ownerName  = body.owner  ? body.owner.name  : '';
const ownerEmail = body.owner  ? body.owner.email : '';
const ccEmails   = body.cc_emails || '';
const networkVer = body.network_version || '';

const ramUsedPct = parseFloat(ram.usage_pct || 0);
const ramFreeGb  = parseFloat(ram.free_gb   || 0).toFixed(1);
const ramTotalGb = parseFloat(ram.total_gb  || 0).toFixed(1);
const ramUsedGb  = parseFloat(ram.used_gb   || 0).toFixed(1);

var worstDisk = rootDisk;
if (allMounts.length > 0) {
  worstDisk = allMounts.reduce(function(w, m) {
    return parseFloat(m.usage_pct||0) > parseFloat(w.usage_pct||0) ? m : w;
  }, allMounts[0]);
}
const diskUsedPct = parseFloat(worstDisk.usage_pct || rootDisk.usage_pct || 0);
const diskFreeGb  = parseFloat(worstDisk.free_gb   || rootDisk.free_gb   || 0).toFixed(1);
const diskTotalGb = parseFloat(worstDisk.total_gb  || rootDisk.total_gb  || 0).toFixed(1);
const diskUsedGb  = parseFloat(worstDisk.used_gb   || rootDisk.used_gb   || 0).toFixed(1);

const maxPct = Math.max(ramUsedPct, diskUsedPct);
var severity = 'OK';
var sevColor = '#27ae60';
if      (maxPct >= 90) { severity = 'CRITICAL'; sevColor = '#c0392b'; }
else if (maxPct >= 80) { severity = 'WARNING';  sevColor = '#e67e22'; }
else if (maxPct >= 70) { severity = 'NOTICE';   sevColor = '#f39c12'; }
else if (maxPct >= 60) { severity = 'INFO';     sevColor = '#2980b9'; }

const activeIssues = issues.filter(function(i){ return i.type && i.type !== 'none'; });

var issueLines = '';
if (activeIssues.length > 0) {
  for (var i = 0; i < activeIssues.length; i++) {
    var iss = activeIssues[i];
    issueLines += '[' + (iss.severity||'').toUpperCase() + '] ' + iss.message;
    if (iss.tier) issueLines += ' (repeats every ' + iss.alert_interval_hours + 'h)';
    issueLines += '\n';
  }
} else {
  issueLines = 'All resources within normal limits';
}

function bar(pct) {
  var f = Math.min(Math.round(pct/10),10);
  var s=''; for(var i=0;i<f;i++) s+='|'; for(var i=0;i<10-f;i++) s+='.';
  return '['+s+'] '+pct+'%';
}

// ── Emoji constants (pure ASCII code points — immune to encoding issues) ──
var fcp = String.fromCodePoint.bind(String);
var fcc = String.fromCharCode.bind(String);
var E = {
  alert:  fcp(0x1F6A8),              // 🚨
  warn:   fcp(0x26A0)+fcp(0xFE0F),   // ⚠️
  notice: fcp(0x1F7E1),              // 🟡
  info:   fcp(0x1F535),              // 🔵
  ok:     fcp(0x2705),               // ✅
  sqRed:  fcp(0x1F7E5),              // 🟥
  sqOrg:  fcp(0x1F7E7),              // 🟧
  sqGrn:  fcp(0x1F7E2),              // 🟢
  win:    fcp(0x1FA9F),              // 🪟
  linux:  fcp(0x1F427),              // 🐧
  ram:    fcp(0x1F4BE),              // 💾
  disk:   fcp(0x1F4BF),              // 💿
  pc:     fcp(0x1F4BB),              // 💻
  pin:    fcp(0x1F4CD),              // 📍
  globe:  fcp(0x1F310),              // 🌐
  clock:  fcp(0x1F553),              // 🕓
  person: fcp(0x1F464),              // 👤
  link:   fcp(0x1F517),              // 🔗
  full:   fcc(0x2588),               // █
  empty:  fcc(0x2591),               // ░
  div:    fcc(0x2500).repeat(22)     // ──────────────────────
};

function tgBar(pct) {
  var filled = Math.min(Math.round(pct / 5), 20);
  var s = '';
  for (var i = 0; i < filled; i++) s += E.full;
  for (var i = 0; i < 20 - filled; i++) s += E.empty;
  return s;
}
function tgSevBadge(sev) {
  if (sev === 'CRITICAL') return E.sqRed + ' CRITICAL';
  if (sev === 'WARNING')  return E.sqOrg + ' WARNING';
  if (sev === 'NOTICE')   return E.notice + ' NOTICE';
  if (sev === 'INFO')     return E.info + ' INFO';
  return E.sqGrn + ' OK';
}
function tgSevIcon(sev) {
  if (sev === 'CRITICAL') return E.alert;
  if (sev === 'WARNING')  return E.warn;
  if (sev === 'NOTICE')   return E.notice;
  if (sev === 'INFO')     return E.info;
  return E.ok;
}

var osIcon  = osType === 'windows' ? E.win : E.linux;
var osLabel = osType === 'windows' ? 'Windows' : 'Linux';

var tgLines = [
  tgSevIcon(severity) + ' <b>VM INFRASTRUCTURE MONITOR</b>',
  E.div,
  E.pc + ' <b>' + hostname + '</b>   ' + E.pin + ' ' + location,
  E.globe + ' <b>IP:</b> ' + primaryIp + '   ' + E.clock + ' ' + timestamp,
  E.person + ' <b>Owner:</b> ' + ownerName + ' (' + ownerEmail + ')   ' + E.link + ' <b>Network:</b> ' + networkVer,
  osIcon + ' <b>OS:</b> ' + osLabel + '   <b>Status:</b> ' + tgSevBadge(severity),
  E.div,
  E.ram + ' <b>RAM USAGE</b>',
  '<code>' + tgBar(ramUsedPct) + '</code>  <b>' + ramUsedPct + '%</b>',
  'Used: <b>' + ramUsedGb + ' GB</b>  |  Free: <b>' + ramFreeGb + ' GB</b>  |  Total: <b>' + ramTotalGb + ' GB</b>',
  ''
];

if (osType === 'windows' && allMounts.length > 0) {
  tgLines.push(E.disk + ' <b>DISK USAGE (All Drives)</b>');
  for (var d = 0; d < allMounts.length; d++) {
    var mnt = allMounts[d];
    var dpct = parseFloat(mnt.usage_pct || 0);
    tgLines.push('<b>' + mnt.mount + '</b>  <code>' + tgBar(dpct) + '</code>  <b>' + dpct + '%</b>');
    tgLines.push('Used: <b>' + parseFloat(mnt.used_gb||0).toFixed(1) + ' GB</b>  |  Free: <b>' + parseFloat(mnt.free_gb||0).toFixed(1) + ' GB</b>  |  Total: <b>' + parseFloat(mnt.total_gb||0).toFixed(1) + ' GB</b>');
    if (d < allMounts.length - 1) tgLines.push('');
  }
} else {
  tgLines.push(E.disk + ' <b>DISK USAGE (/)</b>');
  tgLines.push('<code>' + tgBar(diskUsedPct) + '</code>  <b>' + diskUsedPct + '%</b>');
  tgLines.push('Used: <b>' + diskUsedGb + ' GB</b>  |  Free: <b>' + diskFreeGb + ' GB</b>  |  Total: <b>' + diskTotalGb + ' GB</b>');
}
tgLines.push(E.div);

if (activeIssues.length > 0) {
  tgLines.push(E.warn + ' <b>ACTIVE ISSUES</b>');
  for (var i = 0; i < activeIssues.length; i++) {
    var iss = activeIssues[i];
    var issIcon = (iss.severity==='critical')?E.sqRed:(iss.severity==='warning')?E.sqOrg:(iss.severity==='notice')?E.notice:E.info;
    var tierNote = iss.tier ? ' <i>(repeats every ' + iss.alert_interval_hours + 'h)</i>' : '';
    tgLines.push(issIcon + ' ' + iss.message + tierNote);
  }
} else {
  tgLines.push(E.sqGrn + ' <b>All resources within normal limits</b>');
}
tgLines.push(E.div);
tgLines.push('<i>VM Metrics Reporter \u2013 Auto-generated alert</i>');

var subIcon = (severity==='CRITICAL')?'[CRITICAL]':(severity==='WARNING')?'[WARNING]':(severity==='NOTICE')?'[NOTICE]':(severity==='INFO')?'[INFO]':'[OK]';

// ── Email disk blocks HTML ──
var diskBlocksHtml = '';
if (osType === 'windows' && allMounts.length > 0) {
  for (var d = 0; d < allMounts.length; d++) {
    var mnt  = allMounts[d];
    var dpct = parseFloat(mnt.usage_pct || 0);
    var dclr = dpct>=90?'#c0392b':dpct>=80?'#e67e22':dpct>=70?'#f39c12':dpct>=60?'#2980b9':'#27ae60';
    var dused  = parseFloat(mnt.used_gb ||0).toFixed(1);
    var dfree  = parseFloat(mnt.free_gb ||0).toFixed(1);
    var dtotal = parseFloat(mnt.total_gb||0).toFixed(1);
    diskBlocksHtml += '<table width="100%" cellpadding="0" cellspacing="0" style="margin-bottom:12px"><tr><td style="padding:18px 20px;border:1px solid #e2e8f0;border-radius:12px;background:#fafbfc"><table width="100%" cellpadding="0" cellspacing="0"><tr><td><p style="margin:0;font-size:13px;font-weight:700;color:#475569">&#128191; Disk ' + mnt.mount + '</p></td><td align="right"><p style="margin:0;font-size:22px;font-weight:900;color:' + dclr + '">' + dpct + '%</p></td></tr></table><table width="100%" cellpadding="0" cellspacing="0" style="margin:10px 0 0"><tr><td bgcolor="#e2e8f0" style="border-radius:99px;height:10px;overflow:hidden"><table cellpadding="0" cellspacing="0" width="' + dpct + '%"><tr><td style="height:10px;background:' + dclr + ';border-radius:99px;font-size:1px">&nbsp;</td></tr></table></td></tr></table><table width="100%" cellpadding="0" cellspacing="0" style="margin-top:10px"><tr><td style="text-align:center"><p style="margin:0;font-size:11px;color:#64748b">Used</p><p style="margin:3px 0 0;font-size:14px;font-weight:700;color:#1e293b">' + dused + ' GB</p></td><td style="text-align:center;border-left:1px solid #e2e8f0;border-right:1px solid #e2e8f0"><p style="margin:0;font-size:11px;color:#64748b">Free</p><p style="margin:3px 0 0;font-size:14px;font-weight:700;color:#1e293b">' + dfree + ' GB</p></td><td style="text-align:center"><p style="margin:0;font-size:11px;color:#64748b">Total</p><p style="margin:3px 0 0;font-size:14px;font-weight:700;color:#1e293b">' + dtotal + ' GB</p></td></tr></table></td></tr></table>';
  }
} else {
  var dclr2 = diskUsedPct>=90?'#c0392b':diskUsedPct>=80?'#e67e22':diskUsedPct>=70?'#f39c12':diskUsedPct>=60?'#2980b9':'#27ae60';
  diskBlocksHtml = '<table width="100%" cellpadding="0" cellspacing="0" style="margin-bottom:24px"><tr><td style="padding:18px 20px;border:1px solid #e2e8f0;border-radius:12px;background:#fafbfc"><table width="100%" cellpadding="0" cellspacing="0"><tr><td><p style="margin:0;font-size:13px;font-weight:700;color:#475569">&#128191; Disk Usage (/)</p></td><td align="right"><p style="margin:0;font-size:22px;font-weight:900;color:' + dclr2 + '">' + diskUsedPct + '%</p></td></tr></table><table width="100%" cellpadding="0" cellspacing="0" style="margin:10px 0 0"><tr><td bgcolor="#e2e8f0" style="border-radius:99px;height:10px;overflow:hidden"><table cellpadding="0" cellspacing="0" width="' + diskUsedPct + '%"><tr><td style="height:10px;background:' + dclr2 + ';border-radius:99px;font-size:1px">&nbsp;</td></tr></table></td></tr></table><table width="100%" cellpadding="0" cellspacing="0" style="margin-top:10px"><tr><td style="text-align:center"><p style="margin:0;font-size:11px;color:#64748b">Used</p><p style="margin:3px 0 0;font-size:14px;font-weight:700;color:#1e293b">' + diskUsedGb + ' GB</p></td><td style="text-align:center;border-left:1px solid #e2e8f0;border-right:1px solid #e2e8f0"><p style="margin:0;font-size:11px;color:#64748b">Free</p><p style="margin:3px 0 0;font-size:14px;font-weight:700;color:#1e293b">' + diskFreeGb + ' GB</p></td><td style="text-align:center"><p style="margin:0;font-size:11px;color:#64748b">Total</p><p style="margin:3px 0 0;font-size:14px;font-weight:700;color:#1e293b">' + diskTotalGb + ' GB</p></td></tr></table></td></tr></table>';
}

var osBadgeHtml = '<p style="margin:4px 0 0;font-size:12px;color:rgba(255,255,255,0.8)">' + osIcon + ' ' + osLabel + '</p>';

// sevIconHtml — HTML decimal entities, safe in any email client
var sevIconHtml = severity==='CRITICAL' ? '&#128680;'
                : severity==='WARNING'  ? '&#9888;&#65039;'
                : severity==='NOTICE'   ? '&#128993;'
                : severity==='INFO'     ? '&#128309;'
                : '&#9989;';

return [{json:{
  hostname, location, primaryIp, timestamp,
  hasIssues, severity, sevColor,
  osType, osIcon, osLabel,
  ramUsedPct, diskUsedPct,
  ramUsedGb, ramFreeGb, ramTotalGb,
  diskUsedGb, diskFreeGb, diskTotalGb,
  allMounts,
  issueLines: issueLines.trim(),
  tgMessage: tgLines.join('\n'),
  emailSubject: subIcon+' VM Alert: '+hostname+' | '+timestamp,
  ramBar: bar(ramUsedPct),
  diskBar: bar(diskUsedPct),
  ownerName, ownerEmail, ccEmails, networkVer,
  diskBlocksHtml, osBadgeHtml, sevIconHtml
}}];

// Process ALL input items — not just the first one.
// When multiple servers report at the same time, n8n may batch them into
// a single execution. Using $input.all() ensures every server gets saved.
return $input.all().map(function(inputItem) {

  const body = inputItem.json.body || inputItem.json;

  const ram       = body.ram  || {};
  const disk      = (body.disk && body.disk.root) ? body.disk.root : {};
  const rawMounts = (body.disk && body.disk.all_mounts) ? body.disk.all_mounts : [];
  // Filter snap mounts — read-only squashfs loop devices, always 100%, not real disks
  const allMounts = rawMounts.filter(function(m) {
    return m.mount && !m.mount.startsWith('/snap/');
  });
  const ip        = body.ip  || {};
  const today     = body.report_date || new Date().toISOString().slice(0, 10);
  const osType    = body.os_type || 'linux';

  const ramUsedPct = parseFloat(ram.usage_pct || 0);

  // Linux: show root disk (the script monitors root only)
  // Windows: show worst drive across all_mounts
  var displayDisk = disk;
  if (osType === 'windows' && allMounts.length > 0) {
    displayDisk = allMounts.reduce(function(w, m) {
      return parseFloat(m.usage_pct||0) > parseFloat(w.usage_pct||0) ? m : w;
    }, allMounts[0]);
  }
  const diskUsedPct = parseFloat(displayDisk.usage_pct || disk.usage_pct || 0);

  // Trust the severity the server already sent — it knows what it monitors.
  // Strip emoji prefix from old script format: "🔵 INFO" → "INFO"
  const VALID_SEV = ['CRITICAL', 'WARNING', 'NOTICE', 'INFO', 'OK'];
  const sentSeverity = (body.severity || '').toUpperCase().replace(/[^A-Z]/g, '');
  var severity;
  if (VALID_SEV.includes(sentSeverity)) {
    severity = sentSeverity;
  } else {
    var maxPct = Math.max(ramUsedPct, diskUsedPct);
    if      (maxPct >= 90) severity = 'CRITICAL';
    else if (maxPct >= 80) severity = 'WARNING';
    else if (maxPct >= 70) severity = 'NOTICE';
    else if (maxPct >= 60) severity = 'INFO';
    else                   severity = 'OK';
  }

  const vmName     = body.vm_name || 'unknown';
  const primaryIp  = (ip.primary || ip.all) || 'unknown';
  const location   = body.location        || '';
  const networkVer = body.network_version || '';
  const timestamp  = body.timestamp       || '';
  const ownerName  = body.owner ? body.owner.name  : '';
  const ownerEmail = body.owner ? body.owner.email : '';
  const ccEmails   = body.cc_emails || '';

  const vmData = {
    vm_name:     vmName,
    primaryIp:   primaryIp,
    hostname:    vmName,
    location:    location,
    network:     networkVer,
    severity:    severity,
    os_type:     osType,
    ramUsedPct:  ramUsedPct,
    ramUsedGb:   parseFloat(ram.used_gb   || 0).toFixed(1),
    ramFreeGb:   parseFloat(ram.free_gb   || 0).toFixed(1),
    ramTotalGb:  parseFloat(ram.total_gb  || 0).toFixed(1),
    diskUsedPct: diskUsedPct,
    diskUsedGb:  parseFloat(displayDisk.used_gb  || disk.used_gb  || 0).toFixed(1),
    diskFreeGb:  parseFloat(displayDisk.free_gb  || disk.free_gb  || 0).toFixed(1),
    diskTotalGb: parseFloat(displayDisk.total_gb || disk.total_gb || 0).toFixed(1),
    allMounts:   allMounts,
    timestamp:   timestamp,
    report_date: today,
    ownerName:   ownerName,
    ownerEmail:  ownerEmail,
    ccEmails:    ccEmails,
    activeIssues: (body.resource_issues || []).filter(function(i) {
      if (!i.type || i.type === 'none') return false;
      // Cross-check real metric values to drop old-script hardcoded severities
      if (i.type === 'DISK' || i.type === 'disk') {
        return parseFloat((body.disk && body.disk.root && body.disk.root.usage_pct) || 0) >= 60;
      }
      if (i.type === 'RAM' || i.type === 'ram') {
        return parseFloat((body.ram && body.ram.usage_pct) || 0) >= 60;
      }
      return true;
    })
  };

  return { json: {
    ip:          primaryIp,
    data:        JSON.stringify(vmData).replace(/'/g, "''"),
    vm_name:     vmName,
    report_date: today
  }};

});

const machines = {};
for (const row of $input.all()) {
  try { const m = JSON.parse(row.json.data); machines[m.primaryIp || row.json.ip] = m; } catch(e) {}
}
const ipList = Object.keys(machines);
if (ipList.length === 0) return [{ json: { noData: true } }];

const list = ipList.map(ip => machines[ip]);
const SEV_ORDER = { CRITICAL:0, WARNING:1, NOTICE:2, INFO:3, OK:4 };
list.sort((a,b) => (SEV_ORDER[a.severity]??5)-(SEV_ORDER[b.severity]??5));

const now = new Date().toLocaleString('en-GB', {
  weekday:'long', day:'2-digit', month:'long', year:'numeric', hour:'2-digit', minute:'2-digit'
});

// Emoji helpers
const fcp = String.fromCodePoint.bind(String);
const fcc = String.fromCharCode.bind(String);
const E = {
  alert:  fcp(0x1F6A8), warn:   fcp(0x26A0)+fcp(0xFE0F), ok:     fcp(0x2705),
  sqRed:  fcp(0x1F7E5), sqOrg:  fcp(0x1F7E7), sqGrn:  fcp(0x1F7E2),
  win:    fcp(0x1FA9F), linux:  fcp(0x1F427),
  ram:    fcp(0x1F4BE), disk:   fcp(0x1F4BF),
  chart:  fcp(0x1F4CA), redCir: fcp(0x1F534), orgCir: fcp(0x1F7E0), grnCir: fcp(0x1F7E2),
  full:   fcc(0x2588),  empty:  fcc(0x2591),  div:    fcc(0x2500).repeat(22)
};

const vmCount   = list.length;
const critCount = list.filter(m => m.severity==='CRITICAL').length;
const warnCount = list.filter(m => m.severity==='WARNING').length;
const okCount   = list.filter(m => m.severity!=='CRITICAL' && m.severity!=='WARNING').length;

function pctColor(pct) {
  if(pct>=90) return '#b91c1c'; if(pct>=80) return '#c2410c';
  if(pct>=70) return '#b45309'; if(pct>=60) return '#1d4ed8'; return '#15803d';
}
function barCell(pct, gb) {
  const clr=pctColor(pct), w=Math.min(pct,100);
  return '<td style="padding:16px 18px;vertical-align:middle">'
    +'<table cellpadding="0" cellspacing="0"><tr>'
    +'<td style="padding-right:10px">'
      +'<p style="margin:0;font-size:16px;font-weight:800;color:'+clr+'">'+pct+'%</p>'
      +'<p style="margin:3px 0 0;font-size:12px;color:#9ca3af">'+gb+' GB</p>'
    +'</td>'
    +'<td valign="middle">'
      +'<table cellpadding="0" cellspacing="0" width="64"><tr>'
        +'<td bgcolor="#e5e7eb" style="border-radius:3px;height:6px;overflow:hidden;width:64px">'
          +'<table cellpadding="0" cellspacing="0" width="'+w+'%"><tr>'
            +'<td bgcolor="'+clr+'" style="height:6px;border-radius:3px;font-size:1px">&nbsp;</td>'
          +'</tr></table>'
        +'</td>'
      +'</tr></table>'
    +'</td>'
    +'</tr></table>'
  +'</td>';
}
function diskCell(m) {
  if (m.os_type==='windows' && m.allMounts && m.allMounts.length>0) {
    var html='<td style="padding:12px 18px;vertical-align:middle">';
    for(var d=0;d<m.allMounts.length;d++) {
      var drive=m.allMounts[d], dpct=parseFloat(drive.usage_pct||0), dclr=pctColor(dpct), w=Math.min(dpct,100);
      html+='<table cellpadding="0" cellspacing="0" style="margin-bottom:'+(d<m.allMounts.length-1?'10':'0')+'px"><tr>'
        +'<td style="padding-right:8px">'
          +'<p style="margin:0;font-size:11px;font-weight:700;color:#6b7280">'+drive.mount+'</p>'
          +'<p style="margin:1px 0 0;font-size:14px;font-weight:800;color:'+dclr+'">'+dpct+'%</p>'
          +'<p style="margin:1px 0 0;font-size:11px;color:#9ca3af">'+parseFloat(drive.used_gb||0).toFixed(1)+' GB</p>'
        +'</td>'
        +'<td valign="bottom">'
          +'<table cellpadding="0" cellspacing="0" width="56"><tr>'
            +'<td bgcolor="#e5e7eb" style="border-radius:3px;height:5px;overflow:hidden;width:56px">'
              +'<table cellpadding="0" cellspacing="0" width="'+w+'%"><tr>'
                +'<td bgcolor="'+dclr+'" style="height:5px;border-radius:3px;font-size:1px">&nbsp;</td>'
              +'</tr></table>'
            +'</td>'
          +'</tr></table>'
        +'</td>'
        +'</tr></table>';
    }
    return html+'</td>';
  }
  return barCell(m.diskUsedPct, m.diskUsedGb);
}
function badgeStyle(sev) {
  if(sev==='CRITICAL') return 'background:#fee2e2;color:#b91c1c';
  if(sev==='WARNING')  return 'background:#ffedd5;color:#c2410c';
  if(sev==='NOTICE')   return 'background:#fef3c7;color:#b45309';
  if(sev==='INFO')     return 'background:#dbeafe;color:#1d4ed8';
  return 'background:#dcfce7;color:#15803d';
}
function rowBg(sev,index) {
  if(index%2!==0) return '#fafafa';
  if(sev==='CRITICAL') return '#fff5f5';
  if(sev==='WARNING')  return '#fffbf5';
  return '#ffffff';
}

let rows='';
for(let i=0;i<list.length;i++) {
  const m=list[i];
  const osIcon  = m.os_type==='windows' ? '&#129695;' : '&#128039;';
  const osLabel = m.os_type==='windows' ? 'Windows' : 'Linux';
  rows+=
    '<tr bgcolor="'+rowBg(m.severity,i)+'">'
    +'<td style="padding:16px 18px;vertical-align:middle">'
      +'<p style="margin:0;font-size:16px;font-weight:800;color:#111827">'+(m.hostname||m.vm_name)+'</p>'
      +'<p style="margin:4px 0 0;font-size:11px;color:#6b7280">'+osIcon+' '+osLabel+'</p>'
    +'</td>'
    +'<td style="padding:16px 18px;vertical-align:middle">'
      +'<p style="margin:0;font-size:15px;font-family:monospace;color:#4b5563">'+m.primaryIp+'</p>'
    +'</td>'
    +barCell(m.ramUsedPct, m.ramUsedGb)
    +diskCell(m)
    +'<td style="padding:16px 18px;vertical-align:middle;text-align:center">'
      +'<span style="display:inline-block;padding:8px 20px;border-radius:6px;font-size:17px;font-weight:900;letter-spacing:0.5px;'+badgeStyle(m.severity)+'">'+m.severity+'</span>'
    +'</td>'
    +'</tr>';
}

const html=
  '<!DOCTYPE html><html><head><meta charset="UTF-8"></head>'
  +'<body style="margin:0;padding:0;background:#f3f4f6;font-family:Arial,Helvetica,sans-serif">'
  +'<table width="100%" cellpadding="0" cellspacing="0" bgcolor="#f3f4f6"><tr><td style="padding:28px 12px">'
  +'<table width="100%" cellpadding="0" cellspacing="0" style="border-radius:8px;overflow:hidden;border:1px solid #d1d5db;background:#ffffff">'
  +'<tr><td style="padding:28px 36px;border-bottom:1px solid #e5e7eb">'
    +'<p style="margin:0;font-size:26px;font-weight:800;color:#111827">'+now+'</p>'
  +'</td></tr>'
  +'<tr><td>'
    +'<table width="100%" cellpadding="0" cellspacing="0"><tr>'
      +'<td width="25%" style="padding:22px 0;text-align:center;border-right:1px solid #e5e7eb;border-bottom:1px solid #e5e7eb">'
        +'<p style="margin:0 0 8px;font-size:14px;font-weight:700;color:#6b7280;text-transform:uppercase;letter-spacing:0.6px">Total</p>'
        +'<p style="margin:0;font-size:36px;font-weight:900;color:#111827">'+vmCount+'</p>'
      +'</td>'
      +'<td width="25%" style="padding:22px 0;text-align:center;border-right:1px solid #e5e7eb;border-bottom:1px solid #e5e7eb">'
        +'<p style="margin:0 0 8px;font-size:14px;font-weight:700;color:#6b7280;text-transform:uppercase;letter-spacing:0.6px">Critical</p>'
        +'<p style="margin:0;font-size:36px;font-weight:900;color:'+(critCount>0?'#b91c1c':'#9ca3af')+'">'+critCount+'</p>'
      +'</td>'
      +'<td width="25%" style="padding:22px 0;text-align:center;border-right:1px solid #e5e7eb;border-bottom:1px solid #e5e7eb">'
        +'<p style="margin:0 0 8px;font-size:14px;font-weight:700;color:#6b7280;text-transform:uppercase;letter-spacing:0.6px">Warning</p>'
        +'<p style="margin:0;font-size:36px;font-weight:900;color:'+(warnCount>0?'#c2410c':'#9ca3af')+'">'+warnCount+'</p>'
      +'</td>'
      +'<td width="25%" style="padding:22px 0;text-align:center;border-bottom:1px solid #e5e7eb">'
        +'<p style="margin:0 0 8px;font-size:14px;font-weight:700;color:#6b7280;text-transform:uppercase;letter-spacing:0.6px">OK / INFO</p>'
        +'<p style="margin:0;font-size:36px;font-weight:900;color:'+(okCount===vmCount?'#15803d':'#9ca3af')+'">'+okCount+'</p>'
      +'</td>'
    +'</tr></table>'
  +'</td></tr>'
  +'<tr><td>'
    +'<table width="100%" cellpadding="0" cellspacing="0">'
      +'<tr bgcolor="#f1f5f9">'
        +'<td width="26%" style="padding:14px 18px;font-size:14px;font-weight:700;color:#374151;text-transform:uppercase;border-bottom:2px solid #d1d5db">Hostname</td>'
        +'<td width="20%" style="padding:14px 18px;font-size:14px;font-weight:700;color:#374151;text-transform:uppercase;border-bottom:2px solid #d1d5db">IP</td>'
        +'<td width="18%" style="padding:14px 18px;font-size:14px;font-weight:700;color:#374151;text-transform:uppercase;border-bottom:2px solid #d1d5db">RAM</td>'
        +'<td width="22%" style="padding:14px 18px;font-size:14px;font-weight:700;color:#374151;text-transform:uppercase;border-bottom:2px solid #d1d5db">Disk</td>'
        +'<td width="14%" style="padding:14px 18px;font-size:14px;font-weight:700;color:#374151;text-transform:uppercase;border-bottom:2px solid #d1d5db;text-align:center">Status</td>'
      +'</tr>'
      +rows
    +'</table>'
  +'</td></tr>'
  +'</table></td></tr></table>'
  +'</body></html>';

// Telegram
const tgBar = pct => { const f=Math.min(Math.round(pct/5),20); return E.full.repeat(f)+E.empty.repeat(20-f); };
const sevIcon = sev => ({CRITICAL:E.sqRed, WARNING:E.warn, NOTICE:E.sqGrn, INFO:E.sqGrn, OK:E.ok})[sev]||E.ok;

let tgLines = [
  (critCount>0?E.alert:warnCount>0?E.warn:E.ok)+' <b>VM DAILY CONSOLIDATED REPORT</b>',
  E.div,
  E.chart+' <b>'+vmCount+' servers</b>  |  '+E.redCir+' '+critCount+' critical  |  '+E.orgCir+' '+warnCount+' warning  |  '+E.grnCir+' '+okCount+' ok',
  E.div
];
for(const m of list) {
  const osIcon = m.os_type==='windows' ? E.win : E.linux;
  tgLines.push(sevIcon(m.severity)+' <b>'+(m.hostname||m.vm_name)+'</b>  <code>'+m.primaryIp+'</code>  '+osIcon);
  tgLines.push(E.ram+' RAM: <code>'+tgBar(m.ramUsedPct)+'</code> '+m.ramUsedPct+'%');
  if(m.os_type==='windows' && m.allMounts && m.allMounts.length>0) {
    for(const drive of m.allMounts) {
      const dpct=parseFloat(drive.usage_pct||0);
      tgLines.push(E.disk+' '+drive.mount+': <code>'+tgBar(dpct)+'</code> '+dpct+'%');
    }
  } else {
    tgLines.push(E.disk+' Disk: <code>'+tgBar(m.diskUsedPct)+'</code> '+m.diskUsedPct+'%');
  }
  tgLines.push('');
}
tgLines.push('<i>VM Metrics Reporter \u2014 '+now+'</i>');

const subjectPrefix = critCount>0?'['+critCount+' CRITICAL] ':warnCount>0?'[WARNING] ':'[OK] ';
return [{ json: {
  noData: false,
  emailTo: list[0].ownerEmail||'',
  emailSubject: subjectPrefix+'Daily VM Report \u2014 '+vmCount+' servers \u2014 '+now,
  htmlBody: html,
  tgMessage: tgLines.join('\n')
}}];
